#include <iostream>
#include <cmath>
#include <iomanip>

struct Point {
    int x;
    int y;
};

double calculateDistance(Point p1, Point p2) {
    double dx = p1.x - p2.x;
    double dy = p1.y - p2.y;
    return std::sqrt(dx * dx + dy * dy);
}

int main() {
    Point p1 = {0, 0};
    Point p2 = {1, 1};
    double dist = calculateDistance(p1, p2);
    std::cout << std::fixed << std::setprecision(10) << dist;
    return 0;
}
